import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"70. Leave Without Pay","description":"","frontmatter":{"title":"70. Leave Without Pay","eba":"Biomedical Engineers 2025-2028","topics":["leave","employment","preliminary"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/70-leave-without-pay.md","filePath":"ebas/biomedical-engineers/leave/70-leave-without-pay.md"}'),r={name:"ebas/biomedical-engineers/leave/70-leave-without-pay.md"};function s(i,e,p,l,c,u){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_70-leave-without-pay" tabindex="-1">70. Leave Without Pay <a class="header-anchor" href="#_70-leave-without-pay" aria-label="Permalink to &quot;70. Leave Without Pay&quot;">​</a></h1><p><strong>70.1</strong> Definitions For the purposes of this clause 70 only, continuous service includes:</p><p><strong>(a)</strong> continuous service with one and the same Employer, or</p><p><strong>(b)</strong> continuous service with more than one Employer including institutions or statutory bodies (as defined at subclause 63.1(e) and (j)), and</p><p><strong>(c)</strong> an allowable period of absence (as defined at subclause 63.1(a)).</p><p><strong>70.2</strong> Leave without pay for research or study</p><p><strong>(a)</strong> A full-time or part-time Employee may make an application for a period of up to 12 months unpaid leave where:</p><p><strong>(i)</strong> they have completed six (6) years continuous service, and</p><p><strong>(ii)</strong> the sole purpose of the unpaid leave is to undertake a course of study or research relevant to their work.</p><p><strong>(b)</strong> The onus of proving a sufficient aggregate of service to support a claim for unpaid leave will rest with the Employee.</p><p><strong>(c)</strong> The application must be in writing and include details of the proposed course of study or research and its relevance to the Employee’s work.</p><p><strong>(d)</strong> The Employer will only refuse the application on Reasonable Business Grounds.</p><p><strong>(e)</strong> Subject to the terms of this Agreement, an unpaid leave of absence taken in accordance with this clause will not count towards continuity of service (including for Long Service Leave purposes), however it will not break service.</p><p><strong>70.3</strong> Other leave without pay</p><p><strong>(a)</strong> An Employer is not prohibited from granting discretionary leave without pay:</p><p><strong>(i)</strong> that is longer than 12 months duration, and/or</p><p><strong>(ii)</strong> for a reason other than study or research.</p><p><strong>(b)</strong> Such applications may be granted by agreement only and in accordance with the Employer’s policy.</p><p>DEVELOPMENT</p>',19)])])}const g=t(r,[["render",s]]);export{d as __pageData,g as default};
